const a=`{% block sw_extension_store_landing_page %} <div class="sw-extension-store-landing-page"> <div class="sw-extension-store-landing-page__wrapper"> <div v-if="isLoading" class="sw-extension-store-landing-page__wrapper-loading" > <sw-loader /> <p> {{ $t('sw-extension-store.landing-page.enablingShopwareStore') }} <br> {{ $t('sw-extension-store.landing-page.takeMinutes') }} </p> </div> <div v-else-if="activationStatus !== null" class="sw-extension-store-landing-page__wrapper-activated" > <template v-if="activationStatus === 'error'"> <sw-label appearance="pill" variant="danger" > <mt-icon name="regular-times-circle" size="30px" /> </sw-label> <h2> {{ error && error.title || $t('sw-extension-store.landing-page.activationErrorTitle') }} </h2> <p> {{ error && error.detail || $t('sw-extension-store.landing-page.activationErrorDescription') }} </p> <mt-button variant="primary" @click="activateStore" > {{ $t('sw-extension-store.landing-page.retryButton') }} </mt-button> </template> <template v-else-if="activationStatus === 'success'"> <sw-label appearance="pill" variant="success" > <mt-icon name="regular-check-circle" size="30px" /> </sw-label> <h2> {{ $t('sw-extension-store.landing-page.activationSuccessTitle') }} </h2> <p> {{ $t('sw-extension-store.landing-page.activationSuccessDescription') }} </p> </template> </div> <div v-else class="sw-extension-store-landing-page__wrapper-content" > <img :src="assetFilter('/administration/administration/static/img/extension-store/store_illustration.svg')" alt="" > <span v-if="!insideModal" class="sw-extension-store-landing-page__wrapper-label" > {{ $t('sw-extension-store.landing-page.label') }} </span> <h2> {{ $t('sw-extension-store.landing-page.activationDescriptionTitleFirst') }} <br> {{ $t('sw-extension-store.landing-page.activationDescriptionTitleSecond') }} </h2> <p> {{ $t('sw-extension-store.landing-page.activationDescriptionTitleDescription') }} </p> <mt-button class="sw-extension-store-landing-page__activate_button" variant="primary" @click="activateStore" > {{ $t('sw-extension-store.landing-page.activate') }} </mt-button> </div> </div> </div> {% endblock %}`,i={template:a,inject:["extensionHelperService"],props:{insideModal:{type:Boolean,required:!1,default:!1}},data(){return{isLoading:!1,activationStatus:null,error:null}},computed:{extensionName(){return"SwagExtensionStore"},assetFilter(){return Shopware.Filter.getByName("asset")}},methods:{_reloadPage(){window.location.reload()},activateStore(){this.isLoading=!0,this.activationStatus=null,this.extensionHelperService.downloadAndActivateExtension(this.extensionName).then(()=>{this.activationStatus="success",this._reloadPage()}).catch(e=>{var t;this.activationStatus="error",(t=e==null?void 0:e.response)!=null&&t.data&&Array.isArray(e.response.data.errors)&&e.response.data.errors[0]&&(this.error=e.response.data.errors[0]),Shopware.Utils.debug.error(e)}).finally(()=>{this.isLoading=!1})}}};export{i as default};
